import { useState, useRef, useEffect } from 'react';
import { Search, Bell, X, LogOut } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../config/firebase';
import { collection, query, where, onSnapshot, updateDoc, doc, writeBatch, addDoc, runTransaction } from 'firebase/firestore';
import toast from 'react-hot-toast';

export default function Header() {
    const [showNotifications, setShowNotifications] = useState(false);
    const notificationsRef = useRef<HTMLDivElement>(null);

    const navigate = useNavigate();
    const { currentUser, logout } = useAuth();

    // Fallback info
    const userName = currentUser?.name || 'Nhân viên';
    const userRole = currentUser?.department === 'giamdoc' ? 'Giám Đốc' :
                     currentUser?.department === 'truongphong' ? 'Trưởng Phòng' :
                     currentUser?.department === 'nhanvien' ? 'Nhân Viên' :
                     currentUser?.department === 'sangtao' ? 'Khối Sáng tạo' :
                     currentUser?.department || 'Thành viên';
    const userAvatar = currentUser?.avatar || 'https://i.pravatar.cc/150?img=11';

    const handleLogout = async () => {
        try {
            await logout();
            // Optional: navigate('/login') not strictly needed if ProtectedRoute automatically bounces
            navigate('/login');
        } catch (error) {
            console.error("Logout failed:", error);
        }
    };

    // Close when click outside
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
                setShowNotifications(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const [notifications, setNotifications] = useState<any[]>([]);

    useEffect(() => {
        if (!currentUser?.id) return;
        const q = query(collection(db, 'notifications'), where('userId', '==', String(currentUser.id)));
        const unsubscribe = onSnapshot(q, (snapshot) => {
            const notifs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
            notifs.sort((a: any, b: any) => new Date(b.time).getTime() - new Date(a.time).getTime());
            setNotifications(notifs);
        });
        return () => unsubscribe();
    }, [currentUser]);

    // Timer refs to clean up alarms
    const alarmTimersRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

    useEffect(() => {
        if (!currentUser?.id) return;

        const qTasks = query(collection(db, 'project_tasks'));

        const fireAlarm = async (task: any) => {
            try {
                const taskRef = doc(db, 'project_tasks', task.id);
                // Dùng transaction để đảm bảo chỉ có 1 client duy nhất tạo thông báo
                const shouldNotify = await runTransaction(db, async (transaction) => {
                    const taskDoc = await transaction.get(taskRef);
                    if (!taskDoc.exists() || taskDoc.data().notifiedPassed) {
                        return false;
                    }
                    transaction.update(taskRef, { notifiedPassed: true });
                    return true;
                });
                
                if (shouldNotify) {
                    // Gửi Notification Panel cho toàn bộ những người có liên quan
                    if (task.assignees && task.assignees.length > 0) {
                        for (const assignee of task.assignees) {
                            try {
                                await addDoc(collection(db, 'notifications'), {
                                    userId: String(assignee.id),
                                    title: '⏰ Báo động Hạn chót',
                                    text: `Công việc "${task.title}" đã quá thời gian hoàn thành!`,
                                    time: new Date().toISOString(),
                                    isNew: true,
                                    link: `/projects/${task.projectId || ''}`
                                });
                            } catch(e) {
                                console.error("Lỗi thêm thông báo", e);
                            }
                        }
                    }
                }
            } catch(e) {
                console.error("Lỗi khi báo động task", e);
            }
            if (alarmTimersRef.current[task.id]) delete alarmTimersRef.current[task.id];
        };

        const unsubscribe = onSnapshot(qTasks, (snapshot) => {
            const allTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() as any }));

            allTasks.forEach(task => {
                // Nếu không có hạn chót, đã hoàn thành, hoặc đã từng báo động thì bỏ qua
                if (!task.deadline || task.notifiedPassed || task.status === 'HOÀN THÀNH') {
                    if (alarmTimersRef.current[task.id]) {
                        clearTimeout(alarmTimersRef.current[task.id]);
                        delete alarmTimersRef.current[task.id];
                    }
                    return;
                }

                // Bất kỳ client nào cũng tham gia đánh giá để giúp những người offline vẫn nhận được thông báo
                // Tuy nhiên chỉ báo Toast cho những người dùng liên quan
                const amIAssigned = task.assignees?.some((a: any) => String(a.id) === String(currentUser.id));
                const isDirector = currentUser?.department === 'giamdoc';

                const deadlineDate = new Date(task.deadline);
                const now = new Date();
                const msUntilDeadline = deadlineDate.getTime() - now.getTime();

                const triggerLocalToastAndFireAlarm = () => {
                     // Nếu mình có liên quan thì hiện Toast
                     if (amIAssigned || isDirector) {
                         toast.error(`⏰ BÁO ĐỘNG: Công việc "${task.title}" ĐÃ QUÁ HẠN CHÓT!`, { duration: 10000, position: 'top-center' });
                     }
                     // Chạy background FireAlarm để tạo Notification Panel cho người liên quan (đã chặn trùng trong code của fireAlarm)
                     fireAlarm(task);
                };

                // Nếu thời gian đã lố (hoặc chạm ngưỡng) -> Pinging alarm!
                if (msUntilDeadline <= 0) {
                    triggerLocalToastAndFireAlarm();
                } else if (msUntilDeadline <= 24 * 60 * 60 * 1000) {
                    // Nếu thời gian còn lại dưới 24 giờ, thì cài báo thức (setTimeout)
                    // (setTimeout trong JS chạy quá giới hạn 32 bit int (~24 ngày) sẽ bị lỗi tức thời, nên ta giới hạn quét 24 giờ)
                    if (!alarmTimersRef.current[task.id]) {
                        alarmTimersRef.current[task.id] = setTimeout(() => {
                            triggerLocalToastAndFireAlarm();
                        }, msUntilDeadline);
                    }
                }
            });
        });

        return () => {
            unsubscribe();
            Object.values(alarmTimersRef.current).forEach(clearTimeout);
        };
    }, [currentUser]);

    const handleMarkAllRead = async () => {
        try {
            const batch = writeBatch(db);
            let updated = false;
            notifications.forEach(n => {
                if (n.isNew) {
                    batch.update(doc(db, 'notifications', n.id), { isNew: false });
                    updated = true;
                }
            });
            if (updated) await batch.commit();
        } catch (e) {
            console.error("Lỗi đánh dấu đã đọc", e);
        }
    };

    const handleNotificationClick = async (n: any) => {
        if (n.isNew) {
            await updateDoc(doc(db, 'notifications', n.id), { isNew: false });
        }
        if (n.link) {
            navigate(n.link);
            setShowNotifications(false);
        }
    };

    const unreadCount = notifications.filter(n => n.isNew).length;

    const renderTime = (timeStr: string) => {
        if(!timeStr) return '';
        const d = new Date(timeStr);
        if(isNaN(d.getTime())) return timeStr;
        return d.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}) + ' - ' + d.toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'});
    };

    return (
        <header className="glass-panel header" style={{
            height: 'var(--header-height)',
            position: 'fixed',
            top: '1rem',
            right: '1rem',
            left: 'calc(var(--sidebar-width) + 2rem)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '0 1.5rem',
            zIndex: 90,
        }}>

            <div className="search-bar" style={{
                display: 'flex',
                alignItems: 'center',
                background: 'var(--color-background)',
                padding: '0.5rem 1rem',
                borderRadius: '2rem',
                width: '300px',
                gap: '0.5rem',
                border: '1px solid var(--color-border)'
            }}>
                <Search size={18} color="var(--color-text-light)" />
                <input
                    type="text"
                    placeholder="Tìm kiếm..."
                    style={{
                        border: 'none',
                        background: 'transparent',
                        outline: 'none',
                        color: 'var(--color-text)',
                        width: '100%',
                        fontSize: '0.9rem'
                    }}
                />
            </div>

            <div className="header-actions" style={{
                display: 'flex',
                alignItems: 'center',
                gap: '1rem'
            }}>
                {/* Notifications Dropdown Wrapper */}
                <div ref={notificationsRef} style={{ position: 'relative' }}>
                    <button
                        className="action-btn hover-lift active-bounce"
                        onClick={() => setShowNotifications(!showNotifications)}
                        style={{
                            width: '40px',
                            height: '40px',
                            borderRadius: '50%',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            background: showNotifications ? 'var(--color-border)' : 'var(--color-background)',
                            position: 'relative',
                            transition: 'all var(--transition-fast)'
                        }}
                    >
                        <Bell size={20} color="var(--color-text-light)" />
                        {unreadCount > 0 && (
                            <span style={{
                                position: 'absolute',
                                top: '8px',
                                right: '8px',
                                width: '8px',
                                height: '8px',
                                backgroundColor: 'var(--color-danger)',
                                borderRadius: '50%',
                                border: '2px solid white'
                            }}></span>
                        )}
                    </button>

                    {/* Dropdown Panel */}
                    {showNotifications && (
                        <div className="glass-panel" style={{
                            position: 'absolute',
                            top: 'calc(100% + 10px)',
                            right: '-50px',
                            width: '320px',
                            padding: '1.5rem',
                            display: 'flex',
                            flexDirection: 'column',
                            gap: '1rem',
                            transformOrigin: 'top right',
                            animation: 'dropdownFade 0.2s cubic-bezier(0.16, 1, 0.3, 1)',
                            zIndex: 100
                        }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '0.75rem', borderBottom: '1px solid var(--glass-border)' }}>
                                <h4 style={{ fontWeight: 600, fontSize: '1.1rem' }}>Thông báo mới</h4>
                                <button onClick={() => setShowNotifications(false)} style={{ color: 'var(--color-text-light)' }} className="hover-nav">
                                    <X size={18} />
                                </button>
                            </div>

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', maxHeight: '350px', overflowY: 'auto' }}>
                                {notifications.length === 0 ? (
                                    <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--color-text-light)', fontSize: '0.9rem' }}>Chưa có thông báo nào</div>
                                ) : notifications.map(notification => (
                                    <div key={notification.id} onClick={() => handleNotificationClick(notification)} style={{
                                        display: 'flex', gap: '1rem', padding: '0.75rem', borderRadius: '8px',
                                        background: notification.isNew ? 'rgba(79, 70, 229, 0.05)' : 'transparent',
                                        transition: 'all 0.2s', cursor: 'pointer'
                                    }} className="hover-bg">
                                        <div style={{ width: '8px', height: '8px', minWidth: '8px', borderRadius: '50%', background: notification.isNew ? 'var(--color-primary)' : 'transparent', marginTop: '6px' }} />
                                        <div style={{ flex: 1 }}>
                                            <div style={{ fontSize: '0.9rem', fontWeight: 600, marginBottom: '0.2rem', color: notification.isNew ? 'var(--color-text)' : 'var(--color-text-light)' }}>
                                                {notification.title}
                                            </div>
                                            <div style={{ fontSize: '0.8rem', color: 'var(--color-text-light)', marginBottom: '0.4rem', lineHeight: '1.4' }}>
                                                {notification.text}
                                            </div>
                                            <div style={{ fontSize: '0.7rem', color: 'var(--color-primary)' }}>
                                                {renderTime(notification.time)}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                            {unreadCount > 0 && (
                                <button onClick={handleMarkAllRead} className="btn btn-secondary" style={{ width: '100%', fontSize: '0.85rem' }}>Đánh dấu đã đọc tất cả</button>
                            )}
                        </div>
                    )}
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', borderLeft: '1px solid var(--color-border)', paddingLeft: '1rem' }}>
                    <Link to="/settings" className="profile hover-lift active-bounce glass-hover" style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.75rem',
                        cursor: 'pointer',
                        textDecoration: 'none',
                        color: 'inherit',
                        padding: '0.25rem 0.5rem',
                        borderRadius: '8px'
                    }}>
                        <div style={{ textAlign: 'right' }}>
                            <div style={{ fontSize: '0.9rem', fontWeight: 600 }}>{userName}</div>
                            <div style={{ fontSize: '0.75rem', color: 'var(--color-text-light)', textTransform: 'capitalize' }}>{userRole}</div>
                        </div>
                        <div style={{
                            width: '40px',
                            height: '40px',
                            borderRadius: '50%',
                            background: 'linear-gradient(135deg, var(--color-secondary), var(--color-primary))',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: 'white',
                            overflow: 'hidden',
                            transition: 'transform 0.2s',
                            fontSize: '1.2rem'
                        }}
                            onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.05)'}
                            onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}>
                            {userAvatar.startsWith('http') || userAvatar.startsWith('data:') ? (
                                <img src={userAvatar} alt="Avatar" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            ) : (
                                userAvatar
                            )}
                        </div>
                    </Link>

                    <button
                        onClick={handleLogout}
                        className="action-btn hover-lift active-bounce"
                        title="Đăng xuất khỏi hệ thống"
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            background: 'transparent',
                            border: 'none',
                            color: 'var(--color-danger)',
                            cursor: 'pointer',
                            padding: '0.5rem',
                            borderRadius: '50%',
                            transition: 'backgrounds 0.2s'
                        }}
                    >
                        <LogOut size={20} />
                    </button>
                </div>
            </div>

            <style>{`
        .action-btn:hover {
          background: var(--color-border) !important;
          transform: scale(1.05);
        }
        .hover-bg:hover {
            background-color: var(--color-background) !important;
        }
        @keyframes dropdownFade {
            from { opacity: 0; transform: scale(0.95) translateY(-10px); }
            to { opacity: 1; transform: scale(1) translateY(0); }
        }
      `}</style>
        </header>
    );
}

import { useState, useRef, useEffect } from 'react';
import { Search, Plus, Filter, LayoutGrid, CheckSquare, Calendar, Folder, X, Edit, Trash2, ArrowLeft, File, Download } from 'lucide-react';
import toast from 'react-hot-toast';
import { db, storage } from '../../config/firebase';
import { collection, query, getDocs, addDoc, updateDoc, doc, deleteDoc, where } from 'firebase/firestore';
import { ref, uploadBytesResumable, getDownloadURL, deleteObject } from 'firebase/storage';


export default function ProjectDetail({ project, onBack }: { project: any, onBack: () => void }) {
    const [activeTab, setActiveTab] = useState('Phân công');
    const [tasks, setTasks] = useState<any[]>([]);
    const [team, setTeam] = useState<any[]>([]);
    const [files, setFiles] = useState<any[]>([]);
    const [isLoadingData, setIsLoadingData] = useState(true);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [previewFile, setPreviewFile] = useState<any>(null);

    useEffect(() => {
        const loadAllData = async () => {
            if(!project?.id) return;
            try {
                // Load Tasks - Filter by projectId
                const tasksQ = query(collection(db, 'project_tasks'), where('projectId', '==', String(project.id)));
                const tasksSnap = await getDocs(tasksQ);
                setTasks(tasksSnap.docs.map(doc => ({ id: doc.id, ...doc.data() })));
                
                // Load Team (Global)
                const teamQ = query(collection(db, 'employees'));
                const teamSnap = await getDocs(teamQ);
                const fetchedTeam = teamSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
                setTeam(fetchedTeam);

                // Load Files
                const filesQ = query(collection(db, 'project_files'), where('projectId', '==', String(project.id)));
                const filesSnap = await getDocs(filesQ);
                setFiles(filesSnap.docs.map(doc => ({ id: doc.id, ...doc.data() })));
                
            } catch (error) {
                console.error("Lỗi khi tải dữ liệu dự án:", error);
                toast.error("Lỗi tải chi tiết dự án");
            } finally {
                setIsLoadingData(false);
            }
        };
        loadAllData();
    }, [project.id]);

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            toast.loading('Đang tải file lên Cloud...', { id: 'upload' });
            const uploadedFiles = Array.from(e.target.files);
            
            try {
                const successfulFiles = [];
                for (const f of uploadedFiles) {
                    const fileRef = ref(storage, `projects/${project.id}/${Date.now()}_${f.name}`);
                    const uploadTask = await uploadBytesResumable(fileRef, f);
                    const downloadURL = await getDownloadURL(uploadTask.ref);
                    
                    const fileData = {
                        projectId: String(project.id),
                        name: f.name,
                        size: (f.size / 1024 / 1024).toFixed(2) + ' MB',
                        type: f.type || 'Không xác định',
                        date: new Date().toLocaleDateString('vi-VN'),
                        data: downloadURL,
                        storagePath: uploadTask.ref.fullPath
                    };
                    const docRef = await addDoc(collection(db, 'project_files'), fileData);
                    successfulFiles.push({ id: docRef.id, ...fileData });
                }
                
                setFiles([...successfulFiles, ...files]);
                toast.success('Đã lưu file thành công!', { id: 'upload' });
            } catch (err: any) {
                console.error(err);
                toast.error('Lỗi upload file: ' + err.message, { id: 'upload' });
            }
            e.target.value = '';
        }
    };

    const handleDeleteFile = async (id: string, storagePath?: string) => {
        if (confirm('Bạn có chắc chắn muốn xóa tệp này trên Cloud?')) {
            toast.loading('Đang xóa...', { id: 'del-file' });
            try {
                if (storagePath) {
                    const fileRef = ref(storage, storagePath);
                    await deleteObject(fileRef).catch(e => console.error("Lỗi xóa file kho lưu trữ:", e));
                }
                await deleteDoc(doc(db, 'project_files', id));
                setFiles(files.filter((f: any) => f.id !== id));
                toast.success('Đã xóa tệp', { id: 'del-file' });
            } catch (err: any) {
                toast.error('Lỗi: ' + err.message, { id: 'del-file' });
            }
        }
    };
    
    const [taskSearch, setTaskSearch] = useState('');
    const [teamSearch, setTeamSearch] = useState('');
    
    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTask, setEditingTask] = useState<any>(null);
    const [formData, setFormData] = useState({
        title: '', type: 'THIẾT KẾ', status: 'CHƯA BẮT ĐẦU', deadline: ''
    });

    const filteredTasks = tasks.filter((t: any) => t.title.toLowerCase().includes(taskSearch.toLowerCase()));
    const filteredTeam = team.filter((m: any) => m.name.toLowerCase().includes(teamSearch.toLowerCase()));

    const handleDragStart = (e: React.DragEvent, member: any) => {
        if (member.locked) return;
        e.dataTransfer.setData('memberId', member.id.toString());
    };

    const formatDeadline = (dl: string) => {
        if (!dl) return 'Chưa định';
        if (dl.includes('T')) {
            const date = new Date(dl);
            if (!isNaN(date.getTime())) {
                return date.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}) + ' - ' + date.toLocaleDateString('vi-VN');
            }
        }
        return dl;
    };

    const renderDeadlineText = (task: any) => {
        const text = formatDeadline(task.deadline);
        if (!task.deadline || task.status === 'HOÀN THÀNH') return <span>{text}</span>;
        const isOverdue = new Date(task.deadline).getTime() < new Date().getTime();
        return isOverdue ? <span style={{ color: '#EF4444', fontWeight: 800 }}>{text} (QUÁ HẠN)</span> : <span>{text}</span>;
    };

    const handleDrop = async (e: React.DragEvent, taskId: string) => {
        e.preventDefault();
        const memberId = e.dataTransfer.getData('memberId');
        if (!memberId) return;

        const member = team.find((m: any) => m.id.toString() === memberId);
        if (member) {
            const currentTask = tasks.find(t => t.id === taskId);
            if (!currentTask) return;
            const currentAssignees = currentTask.assignees || (currentTask.assignee ? [currentTask.assignee] : []);
            if (currentAssignees.some((a: any) => a.id === member.id)) return;
            
            const updatedAssignees = [...currentAssignees, { id: member.id, name: member.name, avatar: member.avatar }];
            try {
                await updateDoc(doc(db, 'project_tasks', String(taskId)), { assignees: updatedAssignees });
                setTasks(tasks.map((t: any) => t.id === taskId ? { ...t, assignees: updatedAssignees } : t));
                
                // --- Gửi Notification phân công ---
                await addDoc(collection(db, 'notifications'), {
                    userId: String(member.id),
                    title: 'Được phân công',
                    text: `Dự án ${project?.name || ''}: Bạn được giao nhiệm vụ "${currentTask.title}".`,
                    time: new Date().toISOString(),
                    isNew: true,
                    link: `/projects/${project?.id || ''}`
                });

            } catch (err: any) {
                console.error(err);
                toast.error("Lỗi cập nhật người thực hiện: " + err.message);
            }
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault(); // allow dropping
    };
    
    const handleInlineUpdate = async (task: any, field: string, value: string) => {
        let updateData: any = { [field]: value };
        if (field === 'status') {
             let statusColor = '#F59E0B'; // CHƯA BẮT ĐẦU
             if (value === 'ĐANG LÀM') statusColor = '#ff7d0d';
             if (value === 'HOÀN THÀNH') statusColor = '#10B981';
             if (value === 'NHÁP') statusColor = '#6B7280';
             updateData.statusColor = statusColor;
        } else if (field === 'deadline') {
             updateData.notifiedPassed = false;
        }

        try {
            await updateDoc(doc(db, 'project_tasks', String(task.id)), updateData);
            setTasks(tasks.map((t: any) => t.id === task.id ? { ...t, ...updateData } : t));
            
            if (field === 'deadline' && task.assignees && task.assignees.length > 0) {
                 for (const assignee of task.assignees) {
                     await addDoc(collection(db, 'notifications'), {
                         userId: String(assignee.id),
                         title: 'Hạn chót công việc',
                         text: `Dự án ${project?.name || ''}: Task "${task.title}" vừa đổi hạn chót thành ${formatDeadline(value)}`,
                         time: new Date().toISOString(),
                         isNew: true,
                         link: `/projects/${project?.id || ''}`
                     });
                 }
            }
        } catch (err: any) {
            toast.error('Lỗi: ' + err.message);
        }
    };

    const openModal = (task: any = null) => {
        setEditingTask(task);
        if (task) {
            setFormData({
                title: task.title,
                type: task.type,
                status: task.status,
                deadline: task.deadline
            });
        } else {
            setFormData({
                title: '',
                type: 'THIẾT KẾ',
                status: 'CHƯA BẮT ĐẦU',
                deadline: ''
            });
        }
        setIsModalOpen(true);
    };

    const closeModal = () => {
        setIsModalOpen(false);
        setEditingTask(null);
    };

    const handleSaveTask = async () => {
        if (!formData.title) {
            toast.error('Vui lòng nhập tên công việc!');
            return;
        }
        
        let typeColor = '#4F46E5';
        if (formData.type === 'MEDIA') typeColor = '#8B5CF6';
        if (formData.type === 'CONTENT') typeColor = '#10B981';
        if (formData.type === 'MARKETING') typeColor = '#EC4899';

        let statusColor = '#F59E0B'; // CHƯA BẮT ĐẦU
        if (formData.status === 'ĐANG LÀM') statusColor = '#ff7d0d';
        if (formData.status === 'HOÀN THÀNH') statusColor = '#10B981';
        if (formData.status === 'NHÁP') statusColor = '#6B7280';

        const deadlineText = formatDeadline(formData.deadline);

        toast.loading('Đang lưu công việc...', { id: 'save-task' });
        try {
            if (editingTask) {
                const updateData: any = { ...formData, typeColor, statusColor };
                if (editingTask.deadline !== formData.deadline) updateData.notifiedPassed = false;
                
                await updateDoc(doc(db, 'project_tasks', String(editingTask.id)), updateData);
                setTasks(tasks.map((t: any) => t.id === editingTask.id ? { ...t, ...updateData } : t));
                toast.success('Cập nhật thành công', { id: 'save-task' });

                // --- Gửi Notification báo cập nhật task (bao gồm hạn chót) ---
                if (editingTask.assignees && editingTask.assignees.length > 0) {
                    for (const assignee of editingTask.assignees) {
                        try {
                           await addDoc(collection(db, 'notifications'), {
                               userId: String(assignee.id),
                               title: 'Hạn chót công việc',
                               text: `Dự án ${project?.name || ''}: Task "${formData.title}" cập nhật hạn chót là ${deadlineText}`,
                               time: new Date().toISOString(),
                               isNew: true,
                               link: `/projects/${project?.id || ''}`
                           });
                        } catch (e) {
                           console.error("Lỗi gửi thông báo", e);
                        }
                    }
                }

            } else {
                const newTaskData = {
                    ...formData,
                    projectId: String(project.id),
                    typeColor,
                    statusColor,
                    assignees: [], // Default empty when created
                    notifiedPassed: false
                };
                const docRef = await addDoc(collection(db, 'project_tasks'), newTaskData);
                setTasks([...tasks, { id: docRef.id, ...newTaskData }]);
                toast.success('Đã thêm công việc mới', { id: 'save-task' });
            }
            closeModal();
        } catch (err: any) {
            console.error(err);
            toast.error('Lỗi: ' + err.message, { id: 'save-task' });
        }
    };

    const handleDeleteTask = async (id: string) => {
        if (confirm("Bạn có chắc chắn muốn xóa công việc này khỏi Firebase?")) {
            toast.loading('Đang xóa...', { id: 'del-task' });
            try {
                await deleteDoc(doc(db, 'project_tasks', String(id)));
                setTasks(tasks.filter((t: any) => t.id !== id));
                if (editingTask && editingTask.id === id) closeModal();
                toast.success('Đã xóa', { id: 'del-task' });
            } catch (err: any) {
                toast.error('Lỗi: ' + err.message, { id: 'del-task' });
            }
        }
    };

    const handleRemoveAssignee = async (taskId: string, memberId: number, e: React.MouseEvent) => {
        e.stopPropagation();
        const currentTask = tasks.find(t => t.id === taskId);
        if (!currentTask) return;
        const remainingAssignees = (currentTask.assignees || []).filter((a: any) => a.id !== memberId);
        
        try {
            await updateDoc(doc(db, 'project_tasks', String(taskId)), { assignees: remainingAssignees });
            setTasks(tasks.map((t: any) => t.id === taskId ? { ...t, assignees: remainingAssignees } : t));
        } catch (err: any) {
            toast.error("Lỗi gỡ người thực hiện: " + err.message);
        }
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', backgroundColor: 'var(--color-surface)' }}>
            {/* Top Toolbar */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1.25rem 2rem', borderBottom: '1px solid var(--color-border)' }}>
                <div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--color-text-light)', fontSize: '0.9rem', marginBottom: '0.25rem' }}>
                        <button onClick={onBack} style={{ display: 'flex', alignItems: 'center', gap: '0.2rem', background: 'transparent', border: 'none', color: 'var(--color-primary)', fontWeight: 600, cursor: 'pointer', padding: 0, marginRight: '0.5rem' }} className="hover-text-primary">
                            <ArrowLeft size={16} /> Quay lại
                        </button>
                        <span>Dự án</span>
                        <span>›</span>
                        <span style={{ color: 'var(--color-text)', fontWeight: 600 }}>{project.title}</span>
                        <span>›</span>
                        <span style={{ color: 'var(--color-text)', fontWeight: 600 }}>{activeTab === 'Tài liệu' ? 'Tài liệu dự án' : 'Phân chia công việc'}</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                        <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--color-text)' }}>{activeTab === 'Tài liệu' ? 'Quản lý Dữ liệu Dự án' : 'Phân chia công việc'}</h2>
                        <span style={{ backgroundColor: '#FFE4D6', color: '#ff7d0d', padding: '0.25rem 0.75rem', borderRadius: '4px', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '0.5px' }}>{project.status.toUpperCase()}</span>
                    </div>
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <div style={{ position: 'relative', width: '280px' }}>
                        <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-light)' }} />
                        <input type="text" placeholder="Tìm tên công việc..." value={taskSearch} onChange={(e) => setTaskSearch(e.target.value)} style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.75rem', borderRadius: '2rem', border: '1px solid var(--color-border)', backgroundColor: '#F9FAFB', outline: 'none', fontSize: '0.9rem' }} />
                    </div>
                </div>
            </div>

            {/* Navigation Tabs */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 2rem', borderBottom: '1px solid var(--color-border)', backgroundColor: 'white' }}>
                <div style={{ display: 'flex' }}>
                    {[
                        { id: 'Chế độ Bảng', icon: LayoutGrid }, { id: 'Phân công', icon: CheckSquare },
                        { id: 'Tiến độ', icon: Calendar }, { id: 'Tài liệu', icon: Folder }
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '1.25rem 1rem', border: 'none', background: 'transparent',
                                color: activeTab === tab.id ? '#ff7d0d' : 'var(--color-text-light)', fontWeight: activeTab === tab.id ? 700 : 500, fontSize: '0.9rem', cursor: 'pointer',
                                borderBottom: activeTab === tab.id ? '2px solid #ff7d0d' : '2px solid transparent', position: 'relative', top: '1px'
                            }}
                        >
                            <tab.icon size={16} />
                            {tab.id}
                        </button>
                    ))}
                </div>

                <div style={{ display: 'flex', gap: '0.75rem' }}>
                    {activeTab !== 'Tài liệu' && (
                        <button style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.6rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', background: 'white', fontWeight: 600, fontSize: '0.9rem', cursor: 'pointer' }}>
                            <Filter size={16} /> Lọc nhân sự
                        </button>
                    )}
                    {activeTab === 'Tài liệu' ? (
                        <>
                            <input type="file" multiple ref={fileInputRef} style={{ display: 'none' }} onChange={handleFileUpload} />
                            <button onClick={() => fileInputRef.current?.click()} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.6rem 1.2rem', borderRadius: '0.5rem', border: 'none', background: '#ff7d0d', color: 'white', fontWeight: 600, fontSize: '0.9rem', cursor: 'pointer' }}>
                                Tải lên tài liệu
                            </button>
                        </>
                    ) : (
                        <button onClick={() => openModal()} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.6rem 1.2rem', borderRadius: '0.5rem', border: 'none', background: '#ff7d0d', color: 'white', fontWeight: 600, fontSize: '0.9rem', cursor: 'pointer' }}>
                            <Plus size={18} /> Thêm công việc
                        </button>
                    )}
                </div>
            </div>

            {/* Main Content Area */}
            <div style={{ display: 'flex', flex: 1, backgroundColor: '#F9FAFB', overflow: 'hidden' }}>
                {activeTab === 'Tiến độ' ? (
                    <div style={{ flex: 1, padding: '2rem', overflowY: 'auto' }}>
                        <h3 style={{ fontSize: '0.85rem', fontWeight: 700, color: 'var(--color-text-light)', letterSpacing: '1px', marginBottom: '1.5rem', textTransform: 'uppercase' }}>Bảng Theo Dõi Tiến Độ Từng Đầu Mục</h3>
                        <div style={{ backgroundColor: 'white', borderRadius: '1rem', border: '1px solid var(--color-border)', overflow: 'hidden' }}>
                            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                                <thead style={{ backgroundColor: '#F9FAFB', fontSize: '0.85rem', color: 'var(--color-text-light)' }}>
                                    <tr>
                                        <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Công việc</th>
                                        <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Người thực hiện</th>
                                        <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Hạn chót</th>
                                        <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Trạng thái</th>
                                        <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 600, borderBottom: '1px solid var(--color-border)', width: '25%' }}>Tiến độ</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredTasks.length === 0 ? (
                                        <tr>
                                            <td colSpan={5} style={{ padding: '3rem', textAlign: 'center', color: 'var(--color-text-light)' }}>Chưa có thể công việc nào</td>
                                        </tr>
                                    ) : filteredTasks.map((task: any) => {
                                        let progressPercent = 0;
                                        if (task.status === 'ĐANG LÀM') progressPercent = 50;
                                        if (task.status === 'HOÀN THÀNH') progressPercent = 100;
                                        
                                        return (
                                        <tr key={task.id} style={{ borderBottom: '1px solid var(--color-border)' }} className="hover-bg">
                                            <td style={{ padding: '1rem' }}>
                                                <div style={{ fontWeight: 600, color: 'var(--color-text)', marginBottom: '0.25rem' }}>{task.title}</div>
                                                <span style={{ backgroundColor: `${task.typeColor}15`, color: task.typeColor, padding: '0.2rem 0.6rem', borderRadius: '4px', fontSize: '0.7rem', fontWeight: 800 }}>{task.type}</span>
                                            </td>
                                            <td style={{ padding: '1rem' }}>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                    {task.assignees && task.assignees.length > 0 ? task.assignees.map((a: any, index: number) => (
                                                        <div key={a.id} style={{ position: 'relative', marginLeft: index > 0 ? '-10px' : '0', zIndex: 10 - index }} title={a.name}>
                                                            {a.avatar ? (
                                                                <img src={a.avatar} alt="Assignee" style={{ width: '32px', height: '32px', borderRadius: '50%', border: '2px solid white', objectFit: 'cover' }} />
                                                            ) : (
                                                                <div style={{ width: '32px', height: '32px', borderRadius: '50%', border: '2px solid white', backgroundColor: '#E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: '0.8rem' }}>{a.name.charAt(0)}</div>
                                                            )}
                                                        </div>
                                                    )) : <span style={{ color: 'var(--color-text-light)', fontSize: '0.85rem' }}>Chưa phân công</span>}
                                                </div>
                                            </td>
                                            <td style={{ padding: '1rem', textAlign: 'center', color: task.deadline ? 'var(--color-text)' : 'var(--color-text-light)', fontSize: '0.9rem', fontWeight: 500 }}>
                                                {renderDeadlineText(task)}
                                            </td>
                                            <td style={{ padding: '1rem', textAlign: 'center' }}>
                                                <span style={{ backgroundColor: `${task.statusColor}15`, color: task.statusColor, padding: '0.3rem 0.8rem', borderRadius: '2rem', fontSize: '0.75rem', fontWeight: 800, whiteSpace: 'nowrap' }}>{task.status}</span>
                                            </td>
                                            <td style={{ padding: '1rem' }}>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                                    <div style={{ flex: 1, backgroundColor: '#E5E7EB', height: '8px', borderRadius: '4px', overflow: 'hidden' }}>
                                                        <div style={{ width: `${progressPercent}%`, backgroundColor: task.statusColor, height: '100%', borderRadius: '4px', transition: 'width 0.3s ease' }}></div>
                                                    </div>
                                                    <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--color-text-light)', width: '35px' }}>{progressPercent}%</span>
                                                </div>
                                            </td>
                                        </tr>
                                    )})}
                                </tbody>
                            </table>
                        </div>
                    </div>
                ) : activeTab !== 'Tài liệu' ? (
                    <>
                        <div style={{ flex: 1, padding: '2rem', overflowY: 'auto' }}>
                            <h3 style={{ fontSize: '0.85rem', fontWeight: 700, color: 'var(--color-text-light)', letterSpacing: '1px', marginBottom: '1.5rem', textTransform: 'uppercase' }}>Các đầu việc cần phân công</h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem', paddingBottom: '2rem' }}>
                                {isLoadingData ? (
                                    <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--color-text-light)' }}>Đang tải công việc...</div>
                                ) : filteredTasks.map((task: any) => (
                                    <div key={task.id} style={{ backgroundColor: 'white', borderRadius: '0.75rem', padding: '1.5rem', border: '1px solid var(--color-border)', boxShadow: '0 2px 4px rgba(0,0,0,0.02)', ...(task.status === 'ĐANG LÀM' ? { borderColor: '#ff7d0d', boxShadow: '0 4px 12px rgba(255,125,13,0.1)' } : {})}}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                <h4 style={{ fontSize: '1.1rem', fontWeight: 700, color: 'var(--color-text)' }}>{task.title}</h4>
                                                <button onClick={() => openModal(task)} style={{ background: 'transparent', border: 'none', color: 'var(--color-text-light)', cursor: 'pointer', outline: 'none', padding: '0.2rem' }}><Edit size={16} /></button>
                                            </div>
                                            <span style={{ backgroundColor: `${task.typeColor}15`, color: task.typeColor, padding: '0.2rem 0.6rem', borderRadius: '4px', fontSize: '0.7rem', fontWeight: 800, letterSpacing: '0.5px' }}>{task.type}</span>
                                        </div>

                                        <div style={{ marginBottom: '1.5rem' }}>
                                            <div style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--color-text-light)', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Người thực hiện</div>
                                            <div onDrop={(e) => handleDrop(e, task.id)} onDragOver={handleDragOver} style={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-start', padding: '0.75rem 1rem', minHeight: '60px', flexWrap: 'wrap', gap: '0.5rem', backgroundColor: (task.assignees && task.assignees.length > 0) ? 'transparent' : '#F3F4F6', border: (task.assignees && task.assignees.length > 0) ? '1px solid var(--color-border)' : '1px dashed #D1D5DB', borderRadius: '0.5rem', cursor: 'grab' }}>
                                                {task.assignees && task.assignees.length > 0 ? (
                                                    <div style={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: '0.5rem', width: '100%' }}>
                                                        {task.assignees.map((a: any) => (
                                                            <div key={a.id} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', backgroundColor: '#F9FAFB', border: '1px solid var(--color-border)', borderRadius: '2rem', padding: '0.25rem 0.5rem 0.25rem 0.25rem' }}>
                                                                {a.avatar ? (
                                                                    <img src={a.avatar} alt="Assignee" style={{ width: '28px', height: '28px', borderRadius: '50%', objectFit: 'cover' }} />
                                                                ) : (
                                                                    <div style={{ width: '28px', height: '28px', borderRadius: '50%', backgroundColor: '#E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: '0.8rem' }}>{a.name.charAt(0)}</div>
                                                                )}
                                                                <span style={{ fontWeight: 600, fontSize: '0.85rem' }}>{a.name}</span>
                                                                <button onClick={(e) => handleRemoveAssignee(task.id, a.id, e)} style={{ background: 'transparent', border: 'none', color: '#EF4444', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', width: '20px', height: '20px', borderRadius: '50%', marginLeft: '0.25rem' }} title="Gỡ"><X size={12} /></button>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', color: '#9CA3AF', width: '100%' }}>
                                                        <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Plus size={16} /></div>
                                                        <span style={{ fontSize: '0.9rem' }}>Chưa có người phụ trách (Kéo thả vào đây)</span>
                                                    </div>
                                                )}
                                            </div>
                                        </div>

                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                            <div>
                                                <div style={{ fontSize: '0.7rem', fontWeight: 600, color: 'var(--color-text-light)', marginBottom: '0.25rem', textTransform: 'uppercase' }}>Hạn chót</div>
                                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 600, fontSize: '0.9rem', cursor: 'pointer', position: 'relative' }} title="Nhấn để đổi Hạn chót">
                                                    <Calendar size={14} color="var(--color-danger)" /> {renderDeadlineText(task)}
                                                    <input 
                                                        type="datetime-local" 
                                                        style={{ position: 'absolute', opacity: 0, width: '100%', height: '100%', cursor: 'pointer', zIndex: 10, left: 0, top: 0 }}
                                                        value={task.deadline || ''}
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            try { if ('showPicker' in HTMLInputElement.prototype) (e.target as HTMLInputElement).showPicker(); } catch(err){}
                                                        }}
                                                        onChange={(e) => handleInlineUpdate(task, 'deadline', e.target.value)}
                                                    />
                                                </label>
                                            </div>
                                            <div style={{ textAlign: 'right' }}>
                                                <div style={{ fontSize: '0.7rem', fontWeight: 600, color: 'var(--color-text-light)', marginBottom: '0.25rem', textTransform: 'uppercase' }}>Trạng thái</div>
                                                <div style={{ position: 'relative', display: 'inline-block' }} title="Nhấn để đổi Trạng thái">
                                                    <span style={{ color: task.statusColor, fontWeight: 800, fontSize: '0.75rem', cursor: 'pointer' }}>{task.status} <span style={{fontSize: '0.6rem'}}>▼</span></span>
                                                    <select 
                                                        style={{ position: 'absolute', opacity: 0, width: '100%', height: '100%', left: 0, top: 0, cursor: 'pointer', zIndex: 10 }}
                                                        value={task.status}
                                                        onClick={e => e.stopPropagation()}
                                                        onChange={(e) => handleInlineUpdate(task, 'status', e.target.value)}
                                                    >
                                                        <option value="CHƯA BẮT ĐẦU">CHƯA BẮT ĐẦU</option>
                                                        <option value="NHÁP">NHÁP</option>
                                                        <option value="ĐANG LÀM">ĐANG LÀM</option>
                                                        <option value="HOÀN THÀNH">HOÀN THÀNH</option>
                                                    </select>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                                {filteredTasks.length === 0 && <div style={{ textAlign: 'center', color: 'var(--color-text-light)', padding: '2rem' }}>Chưa có công việc nào.</div>}
                            </div>
                        </div>

                        <div style={{ width: '350px', backgroundColor: 'white', borderLeft: '1px solid var(--color-border)', display: 'flex', flexDirection: 'column' }}>
                            <div style={{ padding: '2rem 1.5rem', borderBottom: '1px solid var(--color-border)' }}>
                                <h3 style={{ fontSize: '0.9rem', fontWeight: 800, color: 'var(--color-text)', letterSpacing: '0.5px', marginBottom: '1.25rem', textTransform: 'uppercase' }}>Danh sách nhân sự</h3>
                                <div style={{ position: 'relative' }}>
                                    <Search size={14} style={{ position: 'absolute', left: '0.75rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-light)' }} />
                                    <input type="text" placeholder="Tìm nhân sự..." value={teamSearch} onChange={(e) => setTeamSearch(e.target.value)} style={{ width: '100%', padding: '0.6rem 1rem 0.6rem 2.25rem', borderRadius: '0.5rem', border: 'none', backgroundColor: '#F3F4F6', outline: 'none', fontSize: '0.85rem' }} />
                                </div>
                            </div>
                            <div style={{ flex: 1, overflowY: 'auto', padding: '1.5rem' }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                    {filteredTeam.map((member: any) => (
                                        <div key={member.id} draggable={!member.locked} onDragStart={(e) => handleDragStart(e, member)} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '1rem', border: '1px solid var(--color-border)', borderRadius: '0.75rem', backgroundColor: 'white', cursor: member.locked ? 'not-allowed' : 'grab', opacity: member.locked ? 0.6 : 1 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                                {member.avatar ? <img src={member.avatar} alt={member.name} style={{ width: '40px', height: '40px', borderRadius: '50%', objectFit: 'cover' }} /> : <div style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>{member.name.charAt(0)}</div>}
                                                <div style={{ pointerEvents: 'none' }}><div style={{ fontWeight: 700, fontSize: '0.95rem', color: 'var(--color-text)' }}>{member.name}</div><div style={{ fontSize: '0.8rem', color: 'var(--color-text-light)' }}>{member.role}</div></div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </>
                ) : (
                    <div style={{ flex: 1, padding: '2rem', overflowY: 'auto' }}>
                        <div>
                            <h3 style={{ fontSize: '0.85rem', fontWeight: 700, color: 'var(--color-text-light)', letterSpacing: '1px', marginBottom: '1.25rem', textTransform: 'uppercase' }}>Tệp cá nhân / Tải lên gần đây</h3>
                            {isLoadingData ? (
                                <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--color-text-light)' }}>Đang tải dữ liệu tệp tin...</div>
                            ) : files.length > 0 ? (
                                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.25rem' }}>
                                    {files.map((file: any) => (
                                        <div key={file.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', backgroundColor: 'white', borderRadius: '0.75rem', padding: '1rem', border: '1px solid var(--color-border)', boxShadow: '0 2px 4px rgba(0,0,0,0.02)', cursor: file.data ? 'pointer' : 'default' }} onClick={() => { if(file.data && file.type?.startsWith('image/')) setPreviewFile(file); }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', overflow: 'hidden' }}>
                                                {file.data && file.type?.startsWith('image/') ? <img src={file.data} alt="Preview" style={{ width: '48px', height: '48px', borderRadius: '0.5rem', objectFit: 'cover' }} /> : <div style={{ backgroundColor: '#F3F4F6', padding: '0.75rem', borderRadius: '0.5rem', color: '#ff7d0d', display: 'flex' }}><File size={24}/></div>}
                                                <div style={{ overflow: 'hidden' }}><div style={{ fontWeight: 600, fontSize: '0.9rem', color: 'var(--color-text)' }}>{file.name}</div><div style={{ fontSize: '0.75rem', color: 'var(--color-text-light)', marginTop: '0.2rem' }}>{file.size}</div></div>
                                            </div>
                                            <div style={{ display: 'flex', gap: '0.5rem' }}>
                                                {file.data && (
                                                    <a href={file.data} target="_blank" rel="noopener noreferrer" onClick={e => e.stopPropagation()} style={{ color: 'var(--color-primary)', display: 'flex', alignItems: 'center', padding: '0.5rem', textDecoration: 'none' }} title="Tải xuống / Xem">
                                                        <Download size={16} />
                                                    </a>
                                                )}
                                                <button onClick={(e) => { e.stopPropagation(); handleDeleteFile(file.id, file.storagePath); }} style={{ background: 'transparent', border: 'none', color: '#EF4444', cursor: 'pointer', padding: '0.5rem' }} title="Xóa tệp"><Trash2 size={16} /></button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--color-text-light)' }}>Chưa có tệp nào được tải lên.</div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* Modal - Add Task */}
            {isModalOpen && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 999, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={closeModal}>
                    <div style={{ width: '100%', maxWidth: '500px', backgroundColor: 'white', borderRadius: '1rem', padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1.5rem', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)' }} onClick={e => e.stopPropagation()}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h3 style={{ fontSize: '1.25rem', fontWeight: 700 }}>{editingTask ? 'Chỉnh sửa Công việc' : 'Thêm Công việc mới'}</h3>
                            <button onClick={closeModal} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-text-light)' }}><X size={20} /></button>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <input type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} style={{ width: '100%', padding: '0.75rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none' }} placeholder="Nhập tên công việc..." />
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                                <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value})} style={{ width: '100%', padding: '0.75rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none' }}>
                                    <option value="THIẾT KẾ">THIẾT KẾ</option><option value="MEDIA">MEDIA</option><option value="CONTENT">CONTENT</option><option value="MARKETING">MARKETING</option>
                                </select>
                                <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})} style={{ width: '100%', padding: '0.75rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none' }}>
                                    <option value="CHƯA BẮT ĐẦU">CHƯA BẮT ĐẦU</option><option value="NHÁP">NHÁP</option><option value="ĐANG LÀM">ĐANG LÀM</option><option value="HOÀN THÀNH">HOÀN THÀNH</option>
                                </select>
                            </div>
                            <div>
                                <div style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--color-text-light)', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Hạn chót & Báo thức</div>
                                <input type="datetime-local" value={formData.deadline || ''} onChange={e => setFormData({...formData, deadline: e.target.value})} style={{ width: '100%', padding: '0.75rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontFamily: 'inherit' }} />
                            </div>
                        </div>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                            <button onClick={handleSaveTask} style={{ flex: 1, padding: '0.75rem', backgroundColor: '#ff7d0d', color: 'white', border: 'none', borderRadius: '0.5rem', fontWeight: 600, cursor: 'pointer' }}>Lưu công việc</button>
                            {editingTask && <button onClick={() => handleDeleteTask(editingTask.id)} style={{ padding: '0.75rem 1rem', backgroundColor: '#FEF2F2', color: '#EF4444', border: '1px solid #FECACA', borderRadius: '0.5rem', fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Trash2 size={18} /></button>}
                        </div>
                    </div>
                </div>
            )}
            
            {/* Preview Document */}
            {previewFile && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.7)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={() => setPreviewFile(null)}>
                    <div style={{ position: 'relative', width: '90%', maxWidth: '900px', maxHeight: '90vh', backgroundColor: 'transparent', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }} onClick={e => e.stopPropagation()}>
                        <div style={{ width: '100%', display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: 'white', padding: '1rem 1.5rem', borderRadius: '0.75rem' }}>
                            <div style={{ fontWeight: 600, color: 'var(--color-text)' }}>{previewFile.name}</div>
                            <button onClick={() => setPreviewFile(null)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-text-light)', padding: '0.2rem' }}><X size={20} /></button>
                        </div>
                        <img src={previewFile.data} alt={previewFile.name} style={{ maxWidth: '100%', maxHeight: 'calc(90vh - 80px)', objectFit: 'contain', borderRadius: '0.5rem', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)' }} />
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Search, Plus, LayoutGrid, List, Folder, Globe, Lock, X, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';
import { db } from '../../config/firebase';
import { collection, query, getDocs, addDoc, serverTimestamp, orderBy, deleteDoc, doc } from 'firebase/firestore';

export default function ProjectList({ onSelectProject }: { onSelectProject: (p: any) => void }) {
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [projects, setProjects] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    
    const [formData, setFormData] = useState({
        title: '',
        description: '',
        status: 'ĐANG CHẠY',
        privacy: 'PUBLIC'
    });

    useEffect(() => {
        loadProjects();
    }, []);

    const loadProjects = async () => {
        try {
            const q = query(collection(db, 'projects'), orderBy('createdAt', 'desc'));
            const snap = await getDocs(q);
            setProjects(snap.docs.map(doc => ({ id: doc.id, ...doc.data() })));
        } catch (error: any) {
            console.error(error);
            try {
                const snap = await getDocs(collection(db, 'projects'));
                setProjects(snap.docs.map(doc => ({ id: doc.id, ...doc.data() })));
            } catch(e) {
               toast.error('Lỗi tải danh sách dự án');
            }
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteProject = async (e: React.MouseEvent, projectId: string) => {
        e.stopPropagation();
        if (window.confirm('Bạn có chắc chắn muốn xóa dự án này? Thao tác này không thể hoàn tác.')) {
            toast.loading('Đang xóa dự án...', { id: 'delete' });
            try {
                await deleteDoc(doc(db, 'projects', projectId));
                setProjects(projects.filter(p => p.id !== projectId));
                toast.success('Đã xóa dự án', { id: 'delete' });
            } catch (error: any) {
                toast.error('Lỗi khi xóa: ' + error.message, { id: 'delete' });
            }
        }
    };

    const handleCreateProject = async () => {
        if (!formData.title) return toast.error('Vui lòng nhập tên dự án');
        toast.loading('Đang tạo dự án...', { id: 'create' });
        try {
            const newDoc = {
                ...formData,
                createdAt: serverTimestamp(),
                taskCount: 0
            };
            const docRef = await addDoc(collection(db, 'projects'), newDoc);
            setProjects([{ id: docRef.id, ...newDoc, createdAt: new Date() }, ...projects]);
            toast.success('Đã tạo dự án mới', { id: 'create' });
            setIsModalOpen(false);
            setFormData({ title: '', description: '', status: 'ĐANG CHẠY', privacy: 'PUBLIC' });
        } catch (error: any) {
            toast.error('Lỗi: ' + error.message, { id: 'create' });
        }
    };

    const filtered = projects.filter(p => p.title.toLowerCase().includes(search.toLowerCase()));

    return (
        <div style={{ padding: '2rem', height: '100%', display: 'flex', flexDirection: 'column' }}>
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '2rem' }}>
                <div>
                    <h2 style={{ fontSize: '1.75rem', fontWeight: 800, marginBottom: '0.25rem', letterSpacing: '-0.5px' }}>Quản lý Dự án</h2>
                    <p style={{ color: 'var(--color-text-light)', fontSize: '0.95rem' }}>Theo dõi và quản lý toàn bộ các dự án, chiến dịch của công ty.</p>
                </div>
                <button onClick={() => setIsModalOpen(true)} className="btn hover-lift active-bounce glass-hover" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', background: 'var(--color-primary)', color: 'white', border: 'none', padding: '0.75rem 1.25rem', borderRadius: '0.5rem', fontWeight: 600, cursor: 'pointer' }}>
                    <Plus size={18} /> Tạo dự án mới
                </button>
            </div>

            {/* Toolbar */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <div style={{ display: 'flex', gap: '1rem', flex: 1 }}>
                    <div style={{ position: 'relative', width: '300px' }}>
                        <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-light)' }} />
                        <input
                            type="text"
                            placeholder="Tìm kiếm dự án..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.75rem', borderRadius: '2rem', border: '1px solid var(--color-border)', backgroundColor: 'white', outline: 'none' }}
                        />
                    </div>
                </div>

                <div style={{ display: 'flex', background: 'white', borderRadius: '0.5rem', border: '1px solid var(--color-border)', overflow: 'hidden' }}>
                    <button onClick={() => setViewMode('grid')} style={{ padding: '0.5rem', background: viewMode === 'grid' ? 'var(--color-background)' : 'transparent', border: 'none', cursor: 'pointer', color: viewMode === 'grid' ? 'var(--color-primary)' : 'var(--color-text-light)' }} className="hover-bg">
                        <LayoutGrid size={18} />
                    </button>
                    <button onClick={() => setViewMode('list')} style={{ padding: '0.5rem', background: viewMode === 'list' ? 'var(--color-background)' : 'transparent', border: 'none', cursor: 'pointer', borderLeft: '1px solid var(--color-border)', color: viewMode === 'list' ? 'var(--color-primary)' : 'var(--color-text-light)' }} className="hover-bg">
                        <List size={18} />
                    </button>
                </div>
            </div>

            {/* Content Area */}
            <div style={{ flex: 1, overflowY: 'auto' }} className="custom-scrollbar">
                {isLoading ? (
                    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--color-text-light)' }}>Đang tải danh sách dự án...</div>
                ) : filtered.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--color-text-light)' }}>
                        <Folder size={48} strokeWidth={1} style={{margin:'0 auto 1rem'}}/>
                        {search ? 'Không tìm thấy dự án nào.' : 'Chưa có dự án nào.'}
                    </div>
                ) : viewMode === 'grid' ? (
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '1.5rem', paddingBottom: '2rem' }}>
                        {filtered.map(project => (
                            <div key={project.id} onClick={() => onSelectProject(project)} className="glass-panel hover-lift active-bounce" style={{ padding: '1.5rem', cursor: 'pointer', display: 'flex', flexDirection: 'column', gap: '1rem', border: '1px solid var(--color-border)', backgroundColor: 'white' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                        {project.privacy === 'PUBLIC' ? <Globe size={16} color="var(--color-text-light)"/> : <Lock size={16} color="#F59E0B" />}
                                        <h3 style={{ fontSize: '1.2rem', fontWeight: 700, margin: 0, color: 'var(--color-heading)' }}>{project.title}</h3>
                                    </div>
                                    <span style={{ fontSize: '0.7rem', fontWeight: 700, padding: '0.2rem 0.6rem', borderRadius: '1rem', backgroundColor: project.status === 'ĐANG CHẠY' ? '#ECFDF5' : '#F3F4F6', color: project.status === 'ĐANG CHẠY' ? '#10B981' : '#6B7280' }}>
                                        {project.status}
                                    </span>
                                </div>
                                <p style={{ fontSize: '0.9rem', color: 'var(--color-text-light)', margin: 0 }}>{project.description || 'Chưa có mô tả'}</p>
                                <div style={{ marginTop: 'auto', borderTop: '1px solid var(--color-border)', paddingTop: '1rem', color: 'var(--color-primary)', fontWeight: 600, fontSize: '0.85rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span>Mở dự án</span>
                                    <button onClick={(e) => handleDeleteProject(e, project.id)} style={{ background: 'transparent', border: 'none', color: '#EF4444', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '0.25rem' }} title="Xóa dự án">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div style={{ backgroundColor: 'white', borderRadius: '1rem', border: '1px solid var(--color-border)', overflow: 'hidden' }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead style={{ backgroundColor: 'var(--color-background)', fontSize: '0.85rem', color: 'var(--color-text-light)' }}>
                                <tr>
                                    <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Tên Dự án</th>
                                    <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}>Trạng thái</th>
                                    <th style={{ padding: '1rem', textAlign: 'right', fontWeight: 600, borderBottom: '1px solid var(--color-border)' }}></th>
                                </tr>
                            </thead>
                            <tbody>
                                {filtered.map(project => (
                                    <tr key={project.id} className="hover-bg" style={{ borderBottom: '1px solid var(--color-border)', cursor: 'pointer' }} onClick={() => onSelectProject(project)}>
                                        <td style={{ padding: '1rem' }}><div style={{ fontWeight: 600, color: 'var(--color-heading)', fontSize: '1rem' }}>{project.title}</div></td>
                                        <td style={{ padding: '1rem' }}><span style={{ fontSize: '0.75rem', fontWeight: 700, padding: '0.3rem 0.6rem', borderRadius: '4px', backgroundColor: project.status === 'ĐANG CHẠY' ? '#ECFDF5' : '#F3F4F6', color: project.status === 'ĐANG CHẠY' ? '#10B981' : '#6B7280' }}>{project.status}</span></td>
                                        <td style={{ padding: '1rem', textAlign: 'right' }}>
                                            <button onClick={(e) => handleDeleteProject(e, project.id)} style={{ background: 'transparent', border: 'none', color: '#EF4444', cursor: 'pointer', display: 'inline-flex', alignItems: 'center', padding: '0.5rem', borderRadius: '0.25rem' }} className="hover-bg" title="Xóa dự án">
                                                <Trash2 size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={() => setIsModalOpen(false)}>
                    <div style={{ width: '500px', backgroundColor: 'white', borderRadius: '1rem', padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }} onClick={e => e.stopPropagation()}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h3 style={{ fontSize: '1.25rem', fontWeight: 700, margin: 0 }}>Tạo Dự án Mới</h3>
                            <button onClick={() => setIsModalOpen(false)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-text-light)' }}><X size={20} /></button>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <input type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} style={{ padding: '0.85rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none' }} placeholder="Tên dự án *" />
                            <textarea value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} style={{ padding: '0.85rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', resize: 'vertical', minHeight: '80px' }} placeholder="Mô tả mục tiêu của dự án..." />
                        </div>
                        <button onClick={handleCreateProject} style={{ padding: '0.85rem', backgroundColor: 'var(--color-primary)', color: 'white', border: 'none', borderRadius: '0.5rem', fontWeight: 600, cursor: 'pointer' }}>Tạo dự án</button>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { createContext, useContext, useEffect, useState } from 'react';
import { auth, db } from '../config/firebase';
import { onAuthStateChanged, signOut as firebaseSignOut } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';

interface UserData {
    id: string;
    email: string;
    name?: string;
    department?: string;
    avatar?: string;
    [key: string]: any;
}

interface AuthContextType {
    currentUser: UserData | null;
    loading: boolean;
    logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
    currentUser: null,
    loading: true,
    logout: async () => {},
});

export const useAuth = () => useContext(AuthContext);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [currentUser, setCurrentUser] = useState<UserData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            if (user) {
                try {
                    const userDoc = await getDoc(doc(db, 'users', user.uid));
                    if (userDoc.exists()) {
                        setCurrentUser({ id: user.uid, email: user.email || '', ...userDoc.data() });
                    } else {
                        setCurrentUser({ id: user.uid, email: user.email || '' });
                    }
                } catch (error) {
                    console.error("Lỗi khi tải thông tin user từ Firestore:", error);
                    setCurrentUser(null);
                }
            } else {
                setCurrentUser(null);
            }
            setLoading(false);
        });

        return unsubscribe;
    }, []);

    const logout = async () => {
        await firebaseSignOut(auth);
    };

    // Vừa bật app, màn hình xoay spinner chờ giải mã Auth từ Firebase thay vì chớp nháy
    if (loading) {
        return (
            <div style={{ height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#f9fafb' }}>
                <div style={{ width: '40px', height: '40px', border: '4px solid #ff7d0d', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
            </div>
        );
    }

    return (
        <AuthContext.Provider value={{ currentUser, loading, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

import { useState, useRef, useEffect } from 'react';
import { User, Bell, Settings as SettingsIcon } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../config/firebase';
import { doc, updateDoc, getDoc, setDoc, query, collection, getDocs, writeBatch } from 'firebase/firestore';
import toast from 'react-hot-toast';
import PageTransition from '../components/PageTransition';

export default function Settings() {
    const [activeTab, setActiveTab] = useState('profile');
    const { currentUser } = useAuth();
    
    const initialProfile = {
        name: currentUser?.name || 'Nhân viên',
        email: currentUser?.email || 'Chưa cập nhật',
        role: currentUser?.department === 'giamdoc' ? 'Giám Đốc' : 
              currentUser?.department === 'truongphong' ? 'Trưởng Phòng' : 
              currentUser?.department === 'nhanvien' ? 'Nhân Viên' : 
              currentUser?.department === 'sangtao' ? 'Khối Sáng tạo' : 
              (currentUser?.department || 'Chức vụ'),
        phone: currentUser?.phone || '',
        address: currentUser?.address || '',
        avatar: currentUser?.avatar || 'https://i.pravatar.cc/150?img=11'
    };

    const [systemConfig, setSystemConfig] = useState({ radius: 1, coords: '21.028511, 105.804817' });
    const [formData, setFormData] = useState(initialProfile);
    const [systemFormData, setSystemFormData] = useState(systemConfig);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Lấy config hệ thống từ Firebase
    useEffect(() => {
        const fetchSystemConfig = async () => {
            try {
                const docRef = doc(db, 'system_settings', 'config');
                const docSnap = await getDoc(docRef);
                if (docSnap.exists()) {
                    setSystemConfig(docSnap.data() as any);
                    setSystemFormData(docSnap.data() as any);
                }
            } catch (err) {
                console.error('Lỗi khi tải cấu hình hệ thống:', err);
            }
        };
        fetchSystemConfig();
    }, []);

    useEffect(() => {
        if (currentUser) {
            const mappedRole = currentUser.department === 'giamdoc' ? 'Giám Đốc' : 
                               currentUser.department === 'truongphong' ? 'Trưởng Phòng' : 
                               currentUser.department === 'nhanvien' ? 'Nhân Viên' : 
                               currentUser.department === 'sangtao' ? 'Khối Sáng tạo' : 
                               (currentUser.department || currentUser.role || initialProfile.role);

            // eslint-disable-next-line
            setFormData({
                name: currentUser.name || initialProfile.name,
                email: currentUser.email || initialProfile.email,
                role: mappedRole,
                phone: currentUser.phone || initialProfile.phone,
                address: currentUser.address || initialProfile.address,
                avatar: currentUser.avatar || initialProfile.avatar
            });
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentUser]);

    const avatarIcons = [
        { bg: '#FFE4D6', emoji: '😊', color: '#ff7d0d' },
        { bg: '#E1E9FF', emoji: '🐾', color: '#4F46E5' },
        { bg: '#D1FAE5', emoji: '🐰', color: '#10B981' },
        { bg: '#EDE9FE', emoji: '🌱', color: '#8B5CF6' },
        { bg: '#FCE7F3', emoji: '🌸', color: '#EC4899' },
        { bg: '#FEF3C7', emoji: '🌻', color: '#F59E0B' },
        { bg: '#CCFBF1', emoji: '🤖', color: '#14B8A6' },
        { bg: '#E0E7FF', emoji: '👩‍💻', color: '#6366F1' },
    ];

    const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            if (file.size > 5 * 1024 * 1024) {
                toast.error('File quá lớn. Vui lòng chọn file dưới 5MB.');
                return;
            }
            const reader = new FileReader();
            reader.onload = (event) => {
                if (event.target?.result) {
                    setFormData({ ...formData, avatar: event.target.result as string });
                }
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSave = async () => {
        const updatedUser = { ...currentUser, ...formData, department: formData.role };
        
        if (currentUser?.id) {
            toast.loading('Đang đồng bộ thay đổi...', { id: 'saveProfile' });
            try {
                // Update 'users' collection
                await updateDoc(doc(db, 'users', currentUser.id), updatedUser);

                // Update 'employees' collection to keep global team list synced
                await updateDoc(doc(db, 'employees', currentUser.id), {
                    name: formData.name,
                    avatar: formData.avatar,
                    phone: formData.phone || '',
                    location: formData.address || ''
                }).catch((e) => console.error("Lỗi update employee", e));

                // Batch update cached user data within any assigned tasks
                try {
                    const qTasks = query(collection(db, 'project_tasks'));
                    const tasksSnap = await getDocs(qTasks);
                    const batch = writeBatch(db);
                    let shouldCommit = false;

                    tasksSnap.forEach(tDoc => {
                        const taskData = tDoc.data();
                        if (taskData.assignees && Array.isArray(taskData.assignees)) {
                            const isAssigned = taskData.assignees.some((a: any) => String(a.id) === String(currentUser.id));
                            if (isAssigned) {
                                const newAssignees = taskData.assignees.map((a: any) => 
                                    String(a.id) === String(currentUser.id) 
                                    ? { ...a, name: formData.name, avatar: formData.avatar } 
                                    : a
                                );
                                batch.update(doc(db, 'project_tasks', tDoc.id), { assignees: newAssignees });
                                shouldCommit = true;
                            }
                        }
                    });

                    if (shouldCommit) {
                        await batch.commit();
                    }
                } catch (batchErr) {
                    console.error("Lỗi cập nhật batch tasks:", batchErr);
                }

                toast.success('Đã đồng bộ thay đổi hồ sơ thành công lên đám mây!', { id: 'saveProfile', duration: 3000 });
                // Reload location to fetch new context and sync app-wide avatar/name
                setTimeout(() => window.location.reload(), 1500);
            } catch (error) {
                console.error('Lỗi khi cập nhật hồ sơ Firestore:', error);
                toast.error('Không thể kết nối máy chủ để lưu thay đổi. Vui lòng thử lại sau.', { id: 'saveProfile' });
            }
        } else {
            toast.error('Lỗi: Hồ sơ này chưa được đồng bộ từ Cloud (Thiếu ID).');
        }
    };

    const handleCancel = () => {
        setFormData(initialProfile);
    };

    return (
        <PageTransition style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
            <div>
                <h2 style={{ fontSize: '1.75rem', fontWeight: 800, marginBottom: '0.25rem', letterSpacing: '-0.5px' }}>Cài đặt Hệ thống</h2>
                <p style={{ color: 'var(--color-text-light)', fontSize: '0.95rem' }}>Quản lý hồ sơ cá nhân và cấu hình vận hành của Smiley Agency.</p>
            </div>

            <div className="glass-panel" style={{ padding: 0, backgroundColor: 'var(--color-surface)', overflow: 'hidden' }}>
                {/* Top Tabs */}
                <div style={{ display: 'flex', borderBottom: '1px solid var(--color-border)', padding: '0 1rem' }}>
                    {[
                        { id: 'profile', icon: User, label: 'Hồ sơ cá nhân' },
                        { id: 'notifications', icon: Bell, label: 'Thông báo' },
                        { id: 'system', icon: SettingsIcon, label: 'Cấu hình hệ thống' }
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '1.25rem 1rem',
                                border: 'none',
                                background: 'transparent',
                                color: activeTab === tab.id ? 'var(--color-primary)' : 'var(--color-text-light)',
                                fontWeight: activeTab === tab.id ? 700 : 500,
                                fontSize: '0.9rem',
                                cursor: 'pointer',
                                borderBottom: activeTab === tab.id ? '2px solid var(--color-primary)' : '2px solid transparent',
                                transition: 'all 0.2s',
                                position: 'relative',
                                top: '1px' // To overlap the container's bottom border
                            }}
                        >
                            <tab.icon size={16} />
                            {tab.label}
                        </button>
                    ))}
                </div>

                {/* Tab Content */}
                <div style={{ padding: '2rem 2.5rem' }}>
                    {activeTab === 'profile' && (
                        <div style={{ display: 'flex', gap: '4rem', alignItems: 'flex-start' }}>
                            {/* Left Column: Avatar */}
                            <div style={{ width: '240px', flexShrink: 0 }}>
                                <h3 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '1.5rem' }}>Ảnh đại diện</h3>

                                <div style={{
                                    border: '1px dashed var(--color-border)',
                                    borderRadius: '1rem',
                                    padding: '1.5rem',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    alignItems: 'center',
                                    marginBottom: '2rem'
                                }}>
                                    {formData.avatar.startsWith('http') || formData.avatar.startsWith('data:') ? (
                                        <img
                                            src={formData.avatar}
                                            alt="Profile Avatar"
                                            style={{ width: '120px', height: '120px', borderRadius: '1rem', objectFit: 'cover', marginBottom: '1rem', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' }}
                                        />
                                    ) : (
                                        <div style={{ width: '120px', height: '120px', borderRadius: '1rem', marginBottom: '1rem', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '4rem', backgroundColor: avatarIcons.find(a => a.emoji === formData.avatar)?.bg || '#FFF' }}>
                                            {formData.avatar}
                                        </div>
                                    )}
                                    <input type="file" ref={fileInputRef} onChange={handleAvatarUpload} accept="image/png, image/jpeg" style={{ display: 'none' }} />
                                    <button onClick={() => fileInputRef.current?.click()} style={{
                                        background: 'none',
                                        border: 'none',
                                        color: 'var(--color-primary)',
                                        fontWeight: 600,
                                        fontSize: '0.9rem',
                                        marginBottom: '0.5rem',
                                        cursor: 'pointer'
                                    }}>
                                        Thay đổi ảnh đại diện
                                    </button>
                                    <span style={{ fontSize: '0.75rem', color: 'var(--color-text-light)', fontWeight: 500 }}>JPG, PNG TỐI ĐA 5MB</span>
                                </div>

                                <div>
                                    <h4 style={{ fontSize: '0.9rem', fontWeight: 600, marginBottom: '1rem', color: 'var(--color-text)' }}>Hoặc chọn biểu tượng đại diện</h4>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '0.75rem' }}>
                                        {avatarIcons.map((icon, i) => (
                                            <button
                                                key={i}
                                                onClick={() => setFormData({ ...formData, avatar: icon.emoji })}
                                                style={{
                                                    width: '100%',
                                                    aspectRatio: '1',
                                                    backgroundColor: icon.bg,
                                                    borderRadius: '50%',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    justifyContent: 'center',
                                                    border: 'none',
                                                    fontSize: '1.25rem',
                                                    cursor: 'pointer',
                                                    transition: 'transform 0.2s'
                                                }}
                                                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.1)'}
                                                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
                                            >
                                                {icon.emoji}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            {/* Right Column: Forms */}
                            <div style={{ flex: 1 }}>
                                {/* Personal Info Section */}
                                <div style={{ marginBottom: '2.5rem' }}>
                                    <h3 style={{ fontSize: '1.2rem', fontWeight: 700, marginBottom: '1.5rem' }}>Thông tin cá nhân</h3>

                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Họ và tên</label>
                                            <input type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem' }} />
                                        </div>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Email công việc</label>
                                            <input type="email" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} disabled style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid transparent', backgroundColor: '#F3F4F6', color: '#6B7280', outline: 'none', fontSize: '0.95rem', cursor: 'not-allowed' }} />
                                        </div>
                                    </div>

                                    <div style={{ marginBottom: '1.5rem' }}>
                                        <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Chức vụ</label>
                                        <input type="text" value={formData.role} onChange={e => setFormData({ ...formData, role: e.target.value })} disabled style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid transparent', backgroundColor: '#F3F4F6', color: '#6B7280', outline: 'none', fontSize: '0.95rem', cursor: 'not-allowed' }} />
                                    </div>

                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', paddingBottom: '2.5rem', borderBottom: '1px solid var(--color-border)' }}>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Số điện thoại</label>
                                            <input type="tel" placeholder="Nhập số điện thoại" value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem' }} />
                                        </div>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Địa chỉ</label>
                                            <input type="text" placeholder="Nhập địa chỉ của bạn" value={formData.address} onChange={e => setFormData({ ...formData, address: e.target.value })} style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem' }} />
                                        </div>
                                    </div>
                                </div>

                                {/* Password Section */}
                                <div>
                                    <h3 style={{ fontSize: '1.2rem', fontWeight: 700, marginBottom: '1.5rem' }}>Đổi mật khẩu</h3>

                                    <div style={{ marginBottom: '1.5rem' }}>
                                        <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Mật khẩu hiện tại</label>
                                        <input type="password" defaultValue="••••••••" style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem', letterSpacing: '2px' }} />
                                    </div>

                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2.5rem' }}>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Mật khẩu mới</label>
                                            <input type="password" placeholder="Nhập mật khẩu mới" style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem' }} />
                                        </div>
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-text)' }}>Xác nhận mật khẩu</label>
                                            <input type="password" placeholder="Xác nhận mật khẩu" style={{ width: '100%', padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontSize: '0.95rem' }} />
                                        </div>
                                    </div>

                                    {/* Action Buttons */}
                                    <div style={{ display: 'flex', justifyContent: 'flex-end', alignItems: 'center', gap: '1.5rem' }}>
                                        <button onClick={handleCancel} style={{
                                            background: 'none',
                                            border: 'none',
                                            color: 'var(--color-text-light)',
                                            fontWeight: 600,
                                            fontSize: '0.9rem',
                                            cursor: 'pointer'
                                        }}>
                                            Hủy bỏ
                                        </button>
                                        <button className="btn btn-primary" onClick={handleSave} style={{
                                            padding: '0.75rem 2rem',
                                            borderRadius: '2rem',
                                            fontWeight: 600,
                                            fontSize: '0.95rem',
                                            border: 'none',
                                            cursor: 'pointer',
                                            color: 'white',
                                            backgroundColor: '#ff7d0d'
                                        }}>
                                            Lưu thay đổi
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'notifications' && (
                        <div>
                            <h3 style={{ fontSize: '1.2rem', fontWeight: 700, marginBottom: '1.5rem' }}>Cấu hình thông báo</h3>
                            <p style={{ color: 'var(--color-text-light)' }}>Đang cập nhật...</p>
                        </div>
                    )}

                    {activeTab === 'system' && (
                        <div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                                <h3 style={{ fontSize: '1.2rem', fontWeight: 700 }}>Cấu hình hệ thống</h3>
                            </div>

                            <div style={{ marginBottom: '2.5rem' }}>
                                <h4 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: '1rem', color: 'var(--color-text)' }}>Chấm công & Vị trí</h4>
                                <div style={{ padding: '1.5rem', border: '1px solid var(--color-border)', borderRadius: '0.75rem', backgroundColor: '#F9FAFB' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                        <div>
                                            <div style={{ fontWeight: 600, color: 'var(--color-text)', marginBottom: '0.25rem' }}>Bán kính chấm công hợp lệ</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--color-text-light)' }}>Khoảng cách tối đa từ vị trí của nhân viên đến công ty ở chế độ "Tại văn phòng Agency".</div>
                                        </div>
                                        <select 
                                            value={systemFormData.radius}
                                            onChange={(e) => setSystemFormData({ ...systemFormData, radius: parseFloat(e.target.value) })}
                                            style={{ padding: '0.5rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', fontWeight: 600, color: 'var(--color-text)', backgroundColor: 'white' }}
                                        >
                                            <option value={0.5}>500m</option>
                                            <option value={1}>1km</option>
                                            <option value={2}>2km</option>
                                            <option value={5}>5km</option>
                                            <option value={0}>Không giới hạn</option>
                                        </select>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <div>
                                            <div style={{ fontWeight: 600, color: 'var(--color-text)', marginBottom: '0.25rem' }}>Tọa độ văn phòng Agency</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--color-text-light)' }}>Vị trí trung tâm để tính khoảng cách (Vĩ độ, Kinh độ).</div>
                                        </div>
                                        <input 
                                            value={systemFormData.coords}
                                            onChange={(e) => setSystemFormData({ ...systemFormData, coords: e.target.value })}
                                            style={{ padding: '0.5rem 1rem', borderRadius: '0.5rem', border: '1px solid var(--color-border)', outline: 'none', width: '200px', fontSize: '0.9rem' }}
                                        />
                                    </div>
                                </div>
                                <div style={{ marginTop: '1.5rem', display: 'flex', justifyContent: 'flex-end' }}>
                                    <button 
                                        className="btn btn-primary" 
                                        onClick={async () => {
                                            toast.loading('Đang lưu cấu hình...', { id: 'save-sys' });
                                            try {
                                                await setDoc(doc(db, 'system_settings', 'config'), systemFormData);
                                                setSystemConfig(systemFormData);
                                                toast.success('Đã lưu cấu hình hệ thống (Bán kính & Tọa độ) lên Cloud!', { id: 'save-sys' });
                                            } catch (err: any) {
                                                console.error(err);
                                                toast.error('Lỗi lưu cấu hình: ' + err.message, { id: 'save-sys' });
                                            }
                                        }}
                                        style={{ padding: '0.75rem 2rem', borderRadius: '2rem', fontWeight: 600, backgroundColor: '#ff7d0d', color: 'white', border: 'none', cursor: 'pointer' }}
                                    >
                                        Lưu cấu hình
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </PageTransition>
    );
}
